ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?studentid_g ?month ?day WHERE {
  ?es a :ExamScores .
  ?s a :Students .
  ?es p:hasStudents ?s .
  ?es p:StudentID ?studentid_g .
  ?es p:Month ?month .
  ?es p:Day ?day .
}
GROUP BY ?studentid_g ?month ?day }
  component: { SELECT ?studentid_g ?day WHERE {
  ?es a :ExamScores .
  ?s a :Students .
  ?es p:hasStudents ?s .
  ?es p:StudentID ?studentid_g .
  ?es p:Day ?day .
}
GROUP BY ?studentid_g ?day }
  component_2: { SELECT ?studentid_g ?month WHERE {
  ?es a :ExamScores .
  ?s a :Students .
  ?es p:hasStudents ?s .
  ?es p:StudentID ?studentid_g .
  ?es p:Month ?month .
}
GROUP BY ?studentid_g ?month }
}
